sql:
SELECT MAX(load_mw) AS max_load
FROM load_data
WHERE region = 'North';

SELECT AVG(load_mw) AS average_load
FROM load_data
WHERE region = 'North';

SELECT MAX(load_mw) AS max_load
FROM load_data
WHERE region = 'North Region';

SELECT average_load
FROM load_summary
WHERE region_id = 1;

external_knowledge:
- Special events are assumed to be events that can affect power load, such as holidays, festivals, or sporting events;
- Regions are geographic areas with unique identifiers and names;
- Average power load is the mean power consumption in megawatts (MW) during a special event;
- Temperature and humidity conditions are the average weather conditions during the special events.

sql:
SELECT load_mw
FROM load_data
WHERE load_mw > 1000;

SELECT region_id, AVG(average_load) AS avg_load
FROM load_summary
GROUP BY region_id;

SELECT region, AVG(load_mw) AS average_load
FROM load_data
GROUP BY region;
